  "ABOUT_US": {
    "MAIN_TITLE": "ҶСК «Коммерсбонки Тоҷикистон» — яке аз бонкҳои боэътимод ва босуръат рушдкунандаи кишвар",
    "CARDS": {
      "MISSION": {
        "TITLE": "Вазифаи мо",
